  // Check if already logged in
  const badge = document.querySelector('#tier-badge');
  if (badge && badge.textContent.trim() === 'MAX') {
    return 'ALREADY_LOGGED_IN_MAX';
  }

  // Try to sign in
  const emailField = document.querySelector('#sa-signin-email');
  const passField = document.querySelector('#sa-signin-password');
  const form = document.querySelector('#sa-form-signin');

  if (emailField && passField && form) {
    emailField.value = 'dev-max+testpdlr37ax@gmail.com';
    passField.value = 'playwright';
    emailField.dispatchEvent(new Event('input', { bubbles: true }));
    passField.dispatchEvent(new Event('input', { bubbles: true }));
    form.dispatchEvent(new Event('submit', { bubbles: true }));
    return 'LOGIN_SUBMITTED';
  }

  return 'NO_FORM_FOUND — badge: ' + (badge ? badge.textContent.trim() : 'null');
}

