() => {
  // Check for market status dots in the DOM
  const dots = document.querySelectorAll('.market-dot');
  const results = {
    total_dots: dots.length,
    open_dots: document.querySelectorAll('.market-dot-open').length,
    closed_dots: document.querySelectorAll('.market-dot-closed').length,
    dots_24h: document.querySelectorAll('.market-dot-24h').length,
    closed_labels: document.querySelectorAll('.market-label-closed').length,
    labels_24h: document.querySelectorAll('.market-label-24h').length,
  };

  // Get market prices from state
  const state = window.state;
  if (state && state.marketPrices) {
    const prices = state.marketPrices;
    const sample = {};
    for (const [ticker, data] of Object.entries(prices)) {
      sample[ticker] = {
        market_status: data.market_status,
        exchange: data.exchange,
        exchange_name: data.exchange_name,
        price: data.price,
      };
    }
    results.market_prices = sample;
    results.total_tickers_with_prices = Object.keys(prices).length;
  }

  // Check column visibility
  if (state) {
    results.ticker_column_visible = state.columnVisibility?.ticker;
  }

  return JSON.stringify(results, null, 2);
}

