() => {
  // Find the scrollable parent that contains the table
  const el = document.querySelector('.news-table-wrap');
  if (el) { el.scrollTop = 400; return 'scrolled .news-table-wrap'; }
  const tbody = document.querySelector('tbody');
  if (tbody && tbody.parentElement) {
    let p = tbody.parentElement;
    while (p && p !== document.body) {
      if (p.scrollHeight > p.clientHeight) {
        p.scrollTop = 400;
        return 'scrolled ' + p.tagName + '#' + p.id + '.' + p.className;
      }
      p = p.parentElement;
    }
  }
  // Just scroll the page
  window.scrollBy(0, 200);
  return 'scrolled window';
}

